 1	import * as React from 'react';
 2	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
 3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 4	import {
 5	  ActionGroup,
 6	  Button,
 7	  ButtonType,
 8	  ButtonVariant,
 9	} from '@patternfly/react-core';
10	import { AttachStorageFormState } from './state';
11	import { checkRequiredValues } from './utils';
12	
13	export const AttachStorageFormFooter = (
14	  props: AttachStorageFormFooterProps
15	) => {
16	  const { state, cancel, onConfirm } = props;
17	  const { t } = useCustomTranslation();
18	  const {
19	    poolName,
20	    replicaSize,
21	    lsoStorageClassName,
22	    inProgress,
23	    errorMessage,
24	    storageClassDetails,
25	    deviceClass,
26	  } = state;
27	  const { name, enableStorageClassEncryption, encryptionKMSID } =
28	    storageClassDetails;
29	  const isDisabled =
30	    checkRequiredValues(
31	      poolName,
32	      replicaSize,
33	      lsoStorageClassName,
34	      name,
35	      enableStorageClassEncryption,
36	      encryptionKMSID,
37	      deviceClass
38	    ) ||
39	    inProgress ||
40	    !!errorMessage;
41	
42	  return (
43	    <ButtonBar errorMessage={state.errorMessage} inProgress={state.inProgress}>
44	      <ActionGroup className="pf-v6-c-form pf-v6-c-form__actions--left pf-v6-u-pb-xl">
45	        <Button
46	          type={ButtonType.button}
47	          variant={ButtonVariant.primary}
48	          data-test-id="confirm-action"
49	          onClick={onConfirm}
50	          isDisabled={isDisabled}
51	        >
52	          {t('Attach')}
53	        </Button>
54	        <Button
55	          type={ButtonType.button}
56	          variant={ButtonVariant.secondary}
57	          data-test-id="cancel-action"
58	          onClick={cancel}
59	        >
60	          {t('Cancel')}
61	        </Button>
62	      </ActionGroup>
63	    </ButtonBar>
64	  );
65	};
66	
67	type AttachStorageFormFooterProps = {
68	  state: AttachStorageFormState;
69	  cancel: () => void;
70	  onConfirm: () => void;
71	};

